SELECT COUNT(*)
FROM SESSION_APPLICATIONS A
WHERE A.SESSION_ID = #{sessionId}
AND A.USER_ID = #{userId}
AND A.STATUS != 'CANCELED'

SELECT sa.user_id
FROM session_applications sa
WHERE sa.session_id = #{sessionId}
AND sa.status = 'CONFIRMED'
AND sa.user_id NOT IN (
SELECT a.user_id
FROM attendances a
WHERE a.session_id = #{sessionId}
)
